+    fn new_timer() {
+        let t = Timer::new(Duration::from_secs(60));
+        assert_eq!(t.remaining(), Duration::from_secs(60));
+        assert!(!t.running());
+        assert!(!t.finished());
+    }
+
+    #[test]
+    fn with_interval() {
+        let t = Timer::with_interval(Duration::from_secs(30), Duration::from_millis(100));
+        assert_eq!(t.interval(), Duration::from_millis(100));
